arguments.argument:
if global.gamePaused=false
{
  if initSolid=1
  {
    if movement>0
    {
      mySolid.xVel=image_xscale
      x+=image_xscale
      movement-=1
      if movement=0
      {
        mySolid.xVel=0
        mySolid.x=x
        if image_xscale=1 {mySolid.x-=16}
      }
    }
  }
}
else
{
  mySolid.xVel=0
}
